import React, { useEffect, useMemo, useState } from 'react'
import Header from './components/Header'
import Footer from './components/Footer'
import VideoPlayer from './components/VideoPlayer'
import VideoList from './components/VideoList'
import { useVideos } from './hooks/useVideos'
import { Video } from './types/Video'

const App: React.FC = () => {
  const {
    videos,
    filteredVideos,
    categories,
    searchTerm,
    setSearchTerm,
    category,
    setCategory,
    sortBy,
    setSortBy,
    loading,
    error,
    likedSet,
    savedSet,
    toggleLike,
    toggleSave,
    incrementViews
  } = useVideos()

  const [selected, setSelected] = useState<Video | null>(null)
  const [grid, setGrid] = useState(true)

  useEffect(() => {
    if (!selected && filteredVideos.length > 0) {
      setSelected(filteredVideos[0])
    }
  }, [filteredVideos, selected])

  const upNext = useMemo(() => {
    return filteredVideos.filter(v => v.id !== selected?.id).slice(0, 6)
  }, [filteredVideos, selected])

  const onSelectVideo = (video: Video) => {
    setSelected(video)
    // increment a view when opening a video card
    setTimeout(() => incrementViews(video.id), 0)
  }

  return (
    <div className="min-h-screen flex flex-col">
      <Header
        searchTerm={searchTerm}
        onSearch={setSearchTerm}
        onToggleLayout={() => setGrid(g => !g)}
        isGrid={grid}
        watchLaterCount={savedSet.size}
      />

      <main className="flex-1">
        <section className="container max-w-6xl mx-auto px-4 mt-6">
          <div className="relative overflow-hidden rounded-xl shadow-md">
            <img
              src="https://images.unsplash.com/photo-1518773553398-650c184e0bb3?w=1600&auto=format&fit=crop&q=80"
              alt="Hero banner"
              className="h-52 w-full object-cover"
            />
            <div className="absolute inset-0 bg-gradient-to-r from-black/70 via-black/30 to-transparent" />
            <div className="absolute inset-0 p-6 flex flex-col justify-center text-white">
              <h1 className="text-2xl sm:text-3xl font-semibold">StreamWave: Discover, Learn, and Get Inspired</h1>
              <p className="mt-2 text-white/90 max-w-2xl">A modern, elegant video experience with curated content across tech, design, travel, and more. Search, sort, and enjoy without distractions.</p>
              <div className="mt-4 flex items-center gap-3">
                <button className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition shadow">
                  Explore Now
                </button>
                <button onClick={() => setCategory('All')} className="px-4 py-2 rounded-lg bg-white/10 backdrop-blur hover:bg-white/20 transition border border-white/20">Show All</button>
              </div>
            </div>
          </div>
        </section>

        <section className="container max-w-6xl mx-auto px-4 mt-6">
          <div className="flex flex-wrap items-center gap-3">
            <div className="flex items-center gap-2 px-3 py-2 rounded-lg bg-gray-100">
              <span className="text-sm text-gray-500">Sort</span>
              <select
                value={sortBy}
                onChange={(e) => setSortBy(e.target.value as any)}
                className="bg-white px-3 py-1 rounded-md shadow-sm border text-sm"
              >
                <option value="relevance">Relevance</option>
                <option value="popular">Most Popular</option>
                <option value="recent">Most Recent</option>
                <option value="length">Length</option>
              </select>
            </div>
            <div className="flex-1 overflow-x-auto">
              <div className="flex items-center gap-2 min-w-max">
                {['All', ...categories].map((c) => (
                  <button
                    key={c}
                    onClick={() => setCategory(c)}
                    className={`px-4 py-2 rounded-full transition shadow-sm whitespace-nowrap ${category === c ? 'bg-blue-600 text-white' : 'bg-white hover:bg-gray-100 border'}`}
                  >
                    {c}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </section>

        <section className="container max-w-6xl mx-auto px-4 mt-6 grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="md:col-span-2 space-y-6">
            <div className="rounded-xl shadow-md bg-white p-0">
              {loading && (
                <div className="p-6">Loading videos...</div>
              )}
              {error && (
                <div className="p-6 text-red-600">{error}</div>
              )}
              {!loading && selected && (
                <VideoPlayer
                  video={selected}
                  isLiked={likedSet.has(selected.id)}
                  isSaved={savedSet.has(selected.id)}
                  onLike={() => toggleLike(selected.id)}
                  onSave={() => toggleSave(selected.id)}
                  onShare={() => {
                    const url = `${window.location.origin}${window.location.pathname}#${selected.id}`
                    if (navigator.clipboard) {
                      navigator.clipboard.writeText(url)
                    }
                    alert('Link copied to clipboard!')
                  }}
                  onPlayed={() => incrementViews(selected.id)}
                />
              )}
            </div>

            <div className="rounded-xl bg-white shadow-md p-4">
              <div className="flex items-center justify-between">
                <h2 className="font-semibold text-lg">Explore more</h2>
                <button
                  onClick={() => setGrid(g => !g)}
                  className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition"
                >
                  {grid ? 'List View' : 'Grid View'}
                </button>
              </div>
              <div className="mt-4">
                <VideoList
                  videos={filteredVideos}
                  layout={grid ? 'grid' : 'list'}
                  onSelect={onSelectVideo}
                  likedSet={likedSet}
                  savedSet={savedSet}
                  onToggleLike={toggleLike}
                  onToggleSave={toggleSave}
                  highlightId={selected?.id}
                />
              </div>
            </div>
          </div>

          <aside className="space-y-4">
            <div className="rounded-xl bg-white shadow-md p-4">
              <h3 className="font-semibold text-lg mb-3">Up Next</h3>
              <VideoList
                videos={upNext}
                layout="list"
                onSelect={onSelectVideo}
                likedSet={likedSet}
                savedSet={savedSet}
                onToggleLike={toggleLike}
                onToggleSave={toggleSave}
                compact
              />
            </div>
            <div className="rounded-xl bg-gradient-to-br from-blue-600 to-indigo-600 text-white p-5 shadow-md">
              <h4 className="text-lg font-semibold">Level up your feed</h4>
              <p className="text-white/90 mt-1">Save videos to watch later and like the ones you love to personalize recommendations.</p>
              <button onClick={() => setCategory('Tech')} className="mt-3 px-4 py-2 rounded-lg bg-white text-blue-700 hover:bg-blue-50 transition">See Tech Picks</button>
            </div>
          </aside>
        </section>
      </main>

      <Footer />
    </div>
  )
}

export default App

