import React from 'react'
import { Video } from '../types/Video'
import VideoItem from './VideoItem'

type Props = {
  videos: Video[]
  layout?: 'grid' | 'list'
  compact?: boolean
  onSelect: (video: Video) => void
  likedSet: Set<string>
  savedSet: Set<string>
  onToggleLike: (id: string) => void
  onToggleSave: (id: string) => void
  highlightId?: string
}

const VideoList: React.FC<Props> = ({ videos, layout = 'grid', compact = false, onSelect, likedSet, savedSet, onToggleLike, onToggleSave, highlightId }) => {
  if (!videos || videos.length === 0) {
    return (
      <div className="p-6 text-center text-gray-500">No videos found. Try another search or category.</div>
    )
  }

  if (layout === 'list') {
    return (
      <div className="space-y-3">
        {videos.map(v => (
          <VideoItem
            key={v.id}
            video={v}
            variant={compact ? 'compact' : 'list'}
            isLiked={likedSet.has(v.id)}
            isSaved={savedSet.has(v.id)}
            onLike={() => onToggleLike(v.id)}
            onSave={() => onToggleSave(v.id)}
            onClick={() => onSelect(v)}
            active={v.id === highlightId}
          />
        ))}
      </div>
    )
  }

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
      {videos.map(v => (
        <VideoItem
          key={v.id}
          video={v}
          variant="grid"
          isLiked={likedSet.has(v.id)}
          isSaved={savedSet.has(v.id)}
          onLike={() => onToggleLike(v.id)}
          onSave={() => onToggleSave(v.id)}
          onClick={() => onSelect(v)}
          active={v.id === highlightId}
        />
      ))}
    </div>
  )
}

export default VideoList

