import React, { useEffect, useMemo, useRef, useState } from 'react'
import { Video } from '../types/Video'

const formatViews = (num: number) => {
  if (num >= 1_000_000) return (num / 1_000_000).toFixed(1).replace(/\.0$/, '') + 'M'
  if (num >= 1_000) return (num / 1_000).toFixed(1).replace(/\.0$/, '') + 'K'
  return String(num)
}

const timeSince = (dateStr: string) => {
  const d = new Date(dateStr).getTime()
  const now = Date.now()
  const diff = Math.max(0, now - d)
  const mins = Math.floor(diff / 60000)
  if (mins < 60) return `${mins}m ago`
  const hrs = Math.floor(mins / 60)
  if (hrs < 24) return `${hrs}h ago`
  const days = Math.floor(hrs / 24)
  if (days < 30) return `${days}d ago`
  const months = Math.floor(days / 30)
  if (months < 12) return `${months}mo ago`
  const years = Math.floor(months / 12)
  return `${years}y ago`
}

type Props = {
  video: Video
  isLiked: boolean
  isSaved: boolean
  onLike: () => void
  onSave: () => void
  onShare: () => void
  onPlayed: () => void
}

const VideoPlayer: React.FC<Props> = ({ video, isLiked, isSaved, onLike, onSave, onShare, onPlayed }) => {
  const [subscribed, setSubscribed] = useState(false)
  const [expanded, setExpanded] = useState(false)
  const videoRef = useRef<HTMLVideoElement | null>(null)
  const key = useMemo(() => video.id, [video.id])

  useEffect(() => {
    setExpanded(false)
  }, [video.id])

  return (
    <div className="rounded-xl overflow-hidden">
      <div className="w-full bg-black">
        <video
          key={key}
          ref={videoRef}
          src={video.source}
          poster={video.thumbnail}
          controls
          className="w-full h-auto max-h-[70vh] bg-black"
          onPlay={() => onPlayed()}
        />
      </div>
      <div className="p-4">
        <h2 className="text-xl font-semibold text-gray-900">{video.title}</h2>
        <div className="mt-2 flex flex-wrap items-center gap-3 text-sm text-gray-600">
          <span>{formatViews(video.views)} views</span>
          <span>•</span>
          <span>{timeSince(video.publishedAt)}</span>
          <span className="px-2 py-0.5 rounded bg-gray-100 text-gray-700">{video.category}</span>
        </div>

        <div className="mt-4 flex flex-wrap items-center justify-between gap-3">
          <div className="flex items-center gap-3">
            <img src={video.channelAvatar} alt={video.channel} className="w-11 h-11 rounded-full object-cover border" />
            <div>
              <div className="font-semibold">{video.channel}</div>
              <div className="text-sm text-gray-500">Verified Creator</div>
            </div>
            <button
              onClick={() => setSubscribed(s => !s)}
              className={`ml-2 px-4 py-2 rounded-lg transition shadow ${subscribed ? 'bg-gray-900 text-white hover:bg-gray-800' : 'bg-blue-600 text-white hover:bg-blue-500'}`}
            >
              {subscribed ? 'Subscribed' : 'Subscribe'}
            </button>
          </div>

          <div className="flex items-center gap-2">
            <button onClick={onLike} className={`px-4 py-2 rounded-lg transition border shadow-sm flex items-center gap-2 ${isLiked ? 'bg-blue-50 border-blue-600 text-blue-700' : 'bg-white hover:bg-gray-50'}`}>
              <svg width="18" height="18" viewBox="0 0 24 24" className={isLiked ? 'fill-blue-600' : 'fill-none'} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14 9V5a3 3 0 00-6 0v4M5 15h10l4-8h-7l-1-2H5v10z"/></svg>
              {isLiked ? 'Liked' : 'Like'}
            </button>
            <button onClick={onSave} className={`px-4 py-2 rounded-lg transition border shadow-sm flex items-center gap-2 ${isSaved ? 'bg-blue-50 border-blue-600 text-blue-700' : 'bg-white hover:bg-gray-50'}`}>
              <svg width="18" height="18" viewBox="0 0 24 24" className={isSaved ? 'fill-blue-600' : 'fill-none'} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 5v14l7-4 7 4V5a2 2 0 00-2-2H7a2 2 0 00-2 2z"/></svg>
              Watch later
            </button>
            <button onClick={onShare} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition shadow">
              Share
            </button>
          </div>
        </div>

        <div className="mt-4 bg-gray-50 rounded-xl p-4">
          <div className="text-sm text-gray-700 whitespace-pre-line line-clamp-3" style={{ WebkitLineClamp: expanded ? 'unset' as any : 3 }}>
            {video.description}
          </div>
          <button onClick={() => setExpanded(e => !e)} className="mt-2 text-blue-700 hover:underline text-sm">
            {expanded ? 'Show less' : 'Show more'}
          </button>
        </div>
      </div>
    </div>
  )
}

export default VideoPlayer

