import { useEffect, useMemo, useState } from 'react'
import { getVideos } from '../utils/api'
import { Video } from '../types/Video'

type SortKey = 'relevance' | 'popular' | 'recent' | 'length'

const LS_LIKES = 'streamwave_likes'
const LS_SAVED = 'streamwave_saved'

export const useVideos = () => {
  const [videos, setVideos] = useState<Video[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  const [searchTerm, setSearchTerm] = useState('')
  const [category, setCategory] = useState<'All' | string>('All')
  const [sortBy, setSortBy] = useState<SortKey>('relevance')

  const [likedSet, setLikedSet] = useState<Set<string>>(() => new Set(JSON.parse(localStorage.getItem(LS_LIKES) || '[]')))
  const [savedSet, setSavedSet] = useState<Set<string>>(() => new Set(JSON.parse(localStorage.getItem(LS_SAVED) || '[]')))

  useEffect(() => {
    const load = async () => {
      try {
        setLoading(true)
        const data = await getVideos()
        setVideos(data)
      } catch (e: any) {
        setError('Failed to load videos')
      } finally {
        setLoading(false)
      }
    }
    load()
  }, [])

  useEffect(() => {
    localStorage.setItem(LS_LIKES, JSON.stringify(Array.from(likedSet)))
  }, [likedSet])
  useEffect(() => {
    localStorage.setItem(LS_SAVED, JSON.stringify(Array.from(savedSet)))
  }, [savedSet])

  const categories = useMemo(() => Array.from(new Set(videos.map(v => v.category))), [videos])

  const filteredVideos = useMemo(() => {
    let list = [...videos]
    if (category !== 'All') list = list.filter(v => v.category === category)
    if (searchTerm.trim()) {
      const q = searchTerm.toLowerCase()
      list = list.filter(v =>
        v.title.toLowerCase().includes(q) ||
        v.channel.toLowerCase().includes(q) ||
        (v.description && v.description.toLowerCase().includes(q))
      )
    }
    switch (sortBy) {
      case 'popular':
        list.sort((a, b) => b.views - a.views)
        break
      case 'recent':
        list.sort((a, b) => +new Date(b.publishedAt) - +new Date(a.publishedAt))
        break
      case 'length':
        const toSecs = (d: string) => {
          const [m, s] = d.split(':').map(Number)
          return (m || 0) * 60 + (s || 0)
        }
        list.sort((a, b) => toSecs(b.duration) - toSecs(a.duration))
        break
      default:
        // relevance: keep as-is
        break
    }
    return list
  }, [videos, searchTerm, category, sortBy])

  const toggleLike = (id: string) => {
    setLikedSet(prev => {
      const next = new Set(prev)
      if (next.has(id)) next.delete(id)
      else next.add(id)
      return next
    })
  }

  const toggleSave = (id: string) => {
    setSavedSet(prev => {
      const next = new Set(prev)
      if (next.has(id)) next.delete(id)
      else next.add(id)
      return next
    })
  }

  const incrementViews = (id: string) => {
    setVideos(prev => prev.map(v => v.id === id ? { ...v, views: v.views + 1 } : v))
  }

  return {
    videos,
    filteredVideos,
    categories,
    searchTerm,
    setSearchTerm,
    category,
    setCategory,
    sortBy,
    setSortBy,
    loading,
    error,
    likedSet,
    savedSet,
    toggleLike,
    toggleSave,
    incrementViews,
  }
}
